function mint(uint256 shares, address receiver) public virtual returns (uint256 assets) {
    assets = previewMint(shares); // No need to check for rounding error, previewMint rounds up.

    // Need to transfer before minting or ERC777s could reenter.
    asset.safeTransferFrom(msg.sender, address(this), assets);

    _mint(receiver, shares);

    emit Deposit(msg.sender, receiver, assets, shares);

    afterDeposit(assets, shares);
}

function validateUserOp(
    PackedUserOperation calldata userOp,
    bytes32 userOpHash,
    uint256 missingAccountFunds
)
    external
    payable
    virtual
    onlyEntryPoint
    payPrefund(missingAccountFunds)
    returns (uint256 validationData)
{
    validationData = _validateSignature(userOp, userOpHash);
    _validateNonce(userOp.nonce);
}

function safeGetPartialAmountFloor(
    uint256 numerator,
    uint256 denominator,
    uint256 target
) internal pure returns (uint256 partialAmount) {
    if (isRoundingErrorFloor(numerator, denominator, target)) {
        LibRichErrorsV06.rrevert(LibMathRichErrorsV06.RoundingError(numerator, denominator, target));
    }

    partialAmount = numerator.safeMul(target).safeDiv(denominator);
    return partialAmount;
}

function _returnExcessEther() private {
    // Send received funds back to msg.sender.
    (bool success, bytes memory data) = payable(msg.sender).call{
        value: address(this).balance
    }("");

    // Revert with an error if the ether transfer failed.
    if (!success) {
        revert EtherReturnTransferFailed(
            msg.sender,
            address(this).balance,
            data
        );
    }
}

function _updateApproval(PermitDetails memory details, address owner, address spender) private {
    uint48 nonce = details.nonce;
    address token = details.token;
    uint160 amount = details.amount;
    uint48 expiration = details.expiration;
    PackedAllowance storage allowed = allowance[owner][token][spender];

    if (allowed.nonce != nonce) revert InvalidNonce();

    allowed.updateAll(amount, expiration, nonce);
    emit Permit(owner, token, spender, amount, expiration, nonce);
}

function setMetadataURL(string calldata metadataURL) external {
  require(isAccount(msg.sender), "Unknown account");
  Account storage account = accounts[msg.sender];
  account.metadataURL = metadataURL;
  emit AccountMetadataURLSet(msg.sender, metadataURL);
}

function removeLegacySigner(bytes32 role) private {
  Account storage account = accounts[msg.sender];

  address signer;
  if (role == ValidatorSigner) {
    signer = account.signers.validator;
    account.signers.validator = address(0);
  } else if (role == AttestationSigner) {
    signer = account.signers.attestation;
    account.signers.attestation = address(0);
  } else if (role == VoteSigner) {
    signer = account.signers.vote;
    account.signers.vote = address(0);
  }
  emit LegacySignerRemoved(msg.sender, signer, role);
}

function isChipSignatureForToken(uint256 tokenId, bytes memory data, bytes memory signature)
        public
        view
        returns (bool)
    {
        bytes32 hash = ECDSA.toEthSignedMessageHash(keccak256(data));
        return SignatureCheckerLib.isValidSignatureNow(_chipIds[tokenId], hash, signature);
    }

function getAggregatorAndRequestHeartbeat(address proxy) external {
  IAggregatorProxy proxyInterface = s_heartbeatList[msg.sender];
  if (address(proxyInterface) != proxy) revert HeartbeatNotPermitted();

  IOffchainAggregator aggregator = IOffchainAggregator(proxyInterface.aggregator());
  aggregator.requestNewRound();
}

function _hasRole(
    bytes32 role,
    address account
) internal view virtual returns (bool status) {
    return
        AccessControlStorage
            .ref(AccessControlStorage.DEFAULT_STORAGE_SLOT)
            .roles[role]
            .members
            .contains(account);
}

function setApprovalForAll(address operator, bool approved) public virtual override {
    address owner = msg.sender;
    require(owner != operator, "APPROVING_SELF");
    isApprovedForAll[owner][operator] = approved;
    emit ApprovalForAll(owner, operator, approved);
}

function permit(address owner, PermitSingle memory permitSingle, bytes calldata signature) external {
    if (block.timestamp > permitSingle.sigDeadline) revert SignatureExpired(permitSingle.sigDeadline);

    // Verify the signer address from the signature.
    signature.verify(_hashTypedData(permitSingle.hash()), owner);

    _updateApproval(permitSingle.details, owner, permitSingle.spender);
}

function propose(
    address[] memory targets,
    uint256[] memory values,
    bytes[] memory calldatas,
    string memory description
) public override(Governor, IGovernor) securityCouncilAssigned(calldatas) returns (uint256) {
    return super.propose(targets, values, calldatas, description);
}

function queue(
    address[] memory targets,
    uint256[] memory values,
    bytes[] memory calldatas,
    bytes32 descriptionHash
) public override securityCouncilAssigned(calldatas) returns (uint256) {
    return super.queue(targets, values, calldatas, descriptionHash);
}

function _execute(
    uint256 proposalId,
    address[] memory targets,
    uint256[] memory values,
    bytes[] memory calldatas,
    bytes32 descriptionHash
) internal override(Governor, GovernorTimelockControl) {
    super._execute(proposalId, targets, values, calldatas, descriptionHash);
}

function _cancel(
    address[] memory targets,
    uint256[] memory values,
    bytes[] memory calldatas,
    bytes32 descriptionHash
) internal override(Governor, GovernorTimelockControl) returns (uint256) {
    return super._cancel(targets, values, calldatas, descriptionHash);
}

function quorum(
    uint256 blockNumber
) public view override(IGovernor, GovernorVotesQuorumFraction) returns (uint256) {
    IZeroExVotes votes = IZeroExVotes(address(token));
    return (votes.getPastQuadraticTotalSupply(blockNumber) * quorumNumerator(blockNumber)) / quorumDenominator();
}

function _getVotes(
    address account,
    uint256 blockNumber,
    bytes memory /*params*/
) internal view virtual override(Governor, GovernorVotes) returns (uint256) {
    return IZeroExVotes(address(token)).getPastQuadraticVotes(account, blockNumber);
}

function getPastVotes(address account, uint256 blockNumber) public view returns (uint256) {
    require(blockNumber < block.number, "ZeroExVotes: block not yet mined");

    Checkpoint memory checkpoint = _checkpointsLookup(_checkpoints[account], blockNumber);
    return checkpoint.votes;
}

function getPastQuadraticVotes(address account, uint256 blockNumber) public view returns (uint256) {
    require(blockNumber < block.number, "ZeroExVotes: block not yet mined");

    Checkpoint memory checkpoint = _checkpointsLookup(_checkpoints[account], blockNumber);
    return checkpoint.quadraticVotes;
}

function delegateToViewImplementation(bytes memory data) public view returns (bytes memory) {
    (bool success, bytes memory returnData) = address(this).staticcall(abi.encodeWithSignature("delegateToImplementation(bytes)", data));
    assembly {
        if eq(success, 0) {
            revert(add(returnData, 0x20), returndatasize())
        }
    }
    return abi.decode(returnData, (bytes));
}

function _setCloseFactor(uint newCloseFactorMantissa) external returns (uint) {
    // Check caller is admin
	require(msg.sender == admin, "only admin can set close factor");

    uint oldCloseFactorMantissa = closeFactorMantissa;
    closeFactorMantissa = newCloseFactorMantissa;
    emit NewCloseFactor(oldCloseFactorMantissa, closeFactorMantissa);

    return uint(Error.NO_ERROR);
}

function assignOperator(
    address operatorToAssign
) external override isController {
    // Ensure the operator being assigned is not the null address.
    if (operatorToAssign == address(0)) {
        revert PauserCanNotBeSetAsZero();
    }

    // Set the given address as the new operator.
    operator = operatorToAssign;

    // Emit an event indicating the operator has been updated.
    emit OperatorUpdated(operatorToAssign);
}

function cancelOrders(
    address pausableZoneAddress,
    SeaportInterface seaportAddress,
    OrderComponents[] calldata orders
) external override {
    // Ensure the caller is the owner.
    if (msg.sender != _owner) {
        revert CallerIsNotOwner();
    }

    // Create a zone object from the zone address.
    PausableZone zone = PausableZone(pausableZoneAddress);

    // Call cancelOrders on the given zone.
    zone.cancelOrders(seaportAddress, orders);
}

function assignPauser(address pauserToAssign) external override {
    // Ensure the caller is the owner.
    if (msg.sender != _owner) {
        revert CallerIsNotOwner();
    }
    // Ensure the pauser to assign is not an invalid address.
    if (pauserToAssign == address(0)) {
        revert PauserCanNotBeSetAsZero();
    }

    // Set the given account as the pauser.
    _pauser = pauserToAssign;

    // Emit an event indicating the pauser has been assigned.
    emit PauserUpdated(pauserToAssign);
}

function assignOperator(
    address pausableZoneAddress,
    address operatorToAssign
) external override {
    // Ensure the caller is the owner.
    if (msg.sender != _owner) {
        revert CallerIsNotOwner();
    }
    // Create a zone object from the zone address.
    PausableZone zone = PausableZone(pausableZoneAddress);

    // Call assignOperator on the zone by passing in the given
    // operator address.
    zone.assignOperator(operatorToAssign);
}

function getPartialAmountFloor(uint256 numerator, uint256 denominator, uint256 multiple)
    internal
    pure
    returns (uint256)
    {
        require(!isRoundingError(numerator, denominator, multiple), "ROUNDING_ERROR");
        return numerator.mul(multiple).div(denominator);
    }

function cancelAccountRecoveryDisablement(
  address smartWallet
) external onlyOwnerOr(Role.CANCELLER) {
  require(smartWallet != address(0), "No smart wallet address provided.");

  // Expire account recovery disablement timelock in question if one exists.
  _expireTimelock(
    this.disableAccountRecovery.selector, abi.encode(smartWallet)
  );

  // Emit an event to signify that the recovery disablement was cancelled.
  emit RecoveryDisablementCancelled(smartWallet);
}

function newKeyRingAndAdditionalKey(
  address userSigningKey,
  address additionalSigningKey,
  bytes calldata signature
) external returns (address keyRing) {
  // Deploy and initialize a keyring instance and emit a corresponding event.
  keyRing = _deployNewKeyRing(userSigningKey);

  // Set the additional key on the newly-deployed keyring.
  DharmaKeyRingImplementationV0Interface(keyRing).takeAdminAction(
    DharmaKeyRingImplementationV0Interface.AdminActionType.AddDualKey,
    uint160(additionalSigningKey),
    signature
  );
}

function getAccountByReferral(string calldata referralLink) public view override returns (uint256) {
    uint256 tokenId = referralLinks[keccak256(abi.encodePacked(referralLink))];
    require(tokenId != 0, "Referral link does not exist");

    return tokenId;
}

function redeemVerify(address cToken, address redeemer, uint redeemAmount, uint redeemTokens) override external {
    // Shh - currently unused
    cToken;
    redeemer;

    // Require tokens is zero or amount is also zero
    if (redeemTokens == 0 && redeemAmount > 0) {
        revert("redeemTokens zero");
    }
}

function delegateTo(address callee, bytes memory data) internal returns (bytes memory) {
    (bool success, bytes memory returnData) = callee.delegatecall(data);
    assembly {
        if eq(success, 0) {
            revert(add(returnData, 0x20), returndatasize())
        }
    }
    return returnData;
}

function getAccountSnapshot(address account) override external view returns (uint, uint, uint, uint) {
    return (
        NO_ERROR,
        accountTokens[account],
        borrowBalanceStoredInternal(account),
        exchangeRateStoredInternal()
    );
}

function checkInterface(
    address token,
    bytes4 interfaceHash
) public view returns (bool) {
    return
        token.safeStaticCallBool(
            abi.encodeWithSelector(
                IERC165.supportsInterface.selector,
                interfaceHash
            ),
            true
        );
}

function setValidParentForEquippableGroup(
    uint64 equippableGroupId,
    address parentAddress,
    uint64 partId
) public virtual onlyOwnerOrContributor {
    _setValidParentForEquippableGroup(
        equippableGroupId,
        parentAddress,
        partId
    );
}

function substr(bytes memory self, uint startIndex) internal pure returns (bytes memory) {
    require(startIndex <= self.length);
    var len = self.length - startIndex;
    var addr = Memory.dataPtr(self);
    return Memory.toBytes(addr + startIndex, len);
}

function _storeRoyaltiesInBasisPoints(uint256 royaltiesInBasisPoints) internal virtual {
    uint256 royaltiesInBasisPointsSlot = _getRoyaltiesInBasisPointsSlot();
    assembly {
        sstore(royaltiesInBasisPointsSlot, royaltiesInBasisPoints)
    }
}

function _loadRoyaltiesInBasisPoints() internal view virtual returns (uint256) {
    uint256 royaltiesInBasisPointsSlot = _getRoyaltiesInBasisPointsSlot();
    uint256 royaltyAmount;
    assembly {
        royaltyAmount := sload(royaltiesInBasisPointsSlot)
    }
    return royaltyAmount;
}

constructor(
    address readOnlyOrderValidatorAddress,
    address seaportValidatorHelperAddress,
    address conduitControllerAddress
) {
    _readOnlyOrderValidator = ReadOnlyOrderValidator(
        readOnlyOrderValidatorAddress
    );
    _helper = SeaportValidatorHelper(seaportValidatorHelperAddress);
    _conduitController = ConduitControllerInterface(
        conduitControllerAddress
    );
}

function broadcastDeploy(uint256 deployerPrivateKey, bytes memory creationCode, bytes memory args, bytes32 salt)
        internal
        returns (address)
    {
        VM.broadcast(deployerPrivateKey);
        return _deploy(creationCode, args, salt);
    }

function permitTransferFrom(
    PermitTransferFrom memory permit,
    SignatureTransferDetails calldata transferDetails,
    address owner,
    bytes calldata signature
) external {
    _permitTransferFrom(permit, transferDetails, owner, permit.hash(), signature);
}

function permitWitnessTransferFrom(
    PermitTransferFrom memory permit,
    SignatureTransferDetails calldata transferDetails,
    address owner,
    bytes32 witness,
    string calldata witnessTypeString,
    bytes calldata signature
) external {
    _permitTransferFrom(
        permit, transferDetails, owner, permit.hashWithWitness(witness, witnessTypeString), signature
    );
}

function openLockGemAndDraw(
        address manager,
        address jug,
        address gemJoin,
        address daiJoin,
        bytes32 ilk,
        uint256 wadC,
        uint256 wadD,
        bool transferFrom
    ) external returns (uint256 cdp);

function moveVotingPower(
        address src,
        address dst,
        uint256 srcBalance,
        uint256 dstBalance,
        uint96 srcBalanceLastUpdated,
        uint96 dstBalanceLastUpdated,
        uint256 amount
    ) external returns (bool);

function validateStrictLogic(
    OrderParameters memory orderParameters,
    address primaryFeeRecipient,
    uint256 primaryFeeBips,
    bool checkCreatorFee
) public view returns (ErrorsAndWarnings memory errorsAndWarnings) {
    return
        _helper.validateStrictLogic(
            orderParameters,
            primaryFeeRecipient,
            primaryFeeBips,
            checkCreatorFee
        );
}
